import{_ as a,o as e,c as s,U as l}from"./chunks/framework.ee26a04d.js";const h=JSON.parse('{"title":"JavaScript文件流","description":"","frontmatter":{"layout":"blog","title":"JavaScript文件流","date":"2022-08-04T06:54:23.816Z"},"headers":[],"relativePath":"js/javascript.md","filePath":"js/javascript.md","lastUpdated":1676532347000}'),n={name:"js/javascript.md"},o=l(`<p>前端对二进制数据的处理</p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><ul><li>Blob: 前端的一个专门用于支持文件操作的二进制对象</li><li>ArrayBuffer：前端的一个通用的二进制缓冲区，类似数组，但在API和特性上却有诸多不同</li><li>Buffer：Node.js提供的一个二进制缓冲区，常用来处理I/O操作</li></ul><h2 id="blob" tabindex="-1">Blob <a class="header-anchor" href="#blob" aria-label="Permalink to &quot;Blob&quot;">​</a></h2><p><code>Blob</code> 全称：<code>Binary Large Object</code></p><p>Blob用来支持文件操作。<code>Blob</code> 对象表示一个二进制文件的数据内容，通常用来<strong>读写文件</strong>。 构造函数File继承了blob的所有属性，可以看作是一种特殊的Blob对象。</p><h3 id="功能" tabindex="-1">功能 <a class="header-anchor" href="#功能" aria-label="Permalink to &quot;功能&quot;">​</a></h3><p><img src="https://img2018.cnblogs.com/blog/1060770/201912/1060770-20191217112525289-384672077.png" alt=""> 通过window.URL.createObjectURL方法可以把一个blob转化为一个Blob URL，并且用做文件下载或者图片显示的链接。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">var blob = new Blob([&quot;Hello World&quot;]);//构造一个blob对象</span></span>
<span class="line"><span style="color:#A6ACCD;">  var url = window.URL.createObjectURL(blob);//转化为blob url</span></span>
<span class="line"><span style="color:#A6ACCD;">  var a = document.getElementById(&quot;h&quot;);//获取dom节点</span></span>
<span class="line"><span style="color:#A6ACCD;">  a.download = &quot;helloworld.txt&quot;;//赋给 a.download属性</span></span>
<span class="line"><span style="color:#A6ACCD;">  a.href = url;//点击链接下载</span></span></code></pre></div><h3 id="文件流下载" tabindex="-1">文件流下载 <a class="header-anchor" href="#文件流下载" aria-label="Permalink to &quot;文件流下载&quot;">​</a></h3><p>后端返回的数据是文件流的时候，需要在axios请求指定responseType：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">responseType: &#39;blob&#39;,  // 需要指定</span></span></code></pre></div><p>创建blob对象，创建reader，监听加载时间，创建a标签，模拟点击事件，移除a标签。这就是一个文件流下载的基本流程：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">const blob = new Blob([res.data]);</span></span>
<span class="line"><span style="color:#A6ACCD;">const reader = new FileReader();//fileReader对象允许 Web 应用程序异步读取存储在用户计算机上的文件（或原始数据缓冲区）的内容</span></span>
<span class="line"><span style="color:#A6ACCD;">reader.readAsDataURL(blob);</span></span>
<span class="line"><span style="color:#A6ACCD;">reader.onload = (e) =&gt; {</span></span>
<span class="line"><span style="color:#A6ACCD;">    const a = document.createElement(&#39;a&#39;);</span></span>
<span class="line"><span style="color:#A6ACCD;">    a.download = fileName;</span></span>
<span class="line"><span style="color:#A6ACCD;">    a.href = e.target.result;</span></span>
<span class="line"><span style="color:#A6ACCD;">    document.body.appendChild(a);</span></span>
<span class="line"><span style="color:#A6ACCD;">    a.click();</span></span>
<span class="line"><span style="color:#A6ACCD;">    document.body.removeChild(a);</span></span>
<span class="line"><span style="color:#A6ACCD;">}</span></span></code></pre></div><h2 id="arraybuffer" tabindex="-1">ArrayBuffer <a class="header-anchor" href="#arraybuffer" aria-label="Permalink to &quot;ArrayBuffer&quot;">​</a></h2><p>是javascript操作二进制数据的一个接口。<code>ArrayBuffer</code> 对象代表储存二进制数据的一段内存，它不能直接读写，只能通过视图（<code>TypedArray</code>视图和<code>DataView</code>视图）来读写，视图的作用是以指定格式解读二进制数据。 <a href="https://note.youdao.com/yws/public/resource/e9cb4307115bb0ffbd0d639ad3e45234/xmlnote/WEBRESOURCE0a025e2378877fdd139b5b83df3e2309/40846" target="_blank" rel="noreferrer"></a></p><p>ArrayBuffer也是一个构造函数，可以分配一段可以存放数据的连续内存区域。</p><h3 id="arraybuffer与普通数组" tabindex="-1">arrayBuffer与普通数组 <a class="header-anchor" href="#arraybuffer与普通数组" aria-label="Permalink to &quot;arrayBuffer与普通数组&quot;">​</a></h3><p><a href="https://note.youdao.com/yws/public/resource/e9cb4307115bb0ffbd0d639ad3e45234/xmlnote/WEBRESOURCE16c7d6a4cc7763e55d9edbbf558f5cc3/40914" target="_blank" rel="noreferrer"></a></p><h3 id="视图" tabindex="-1">视图 <a class="header-anchor" href="#视图" aria-label="Permalink to &quot;视图&quot;">​</a></h3><p>操作arraybuffer对象，必须使用视图 <a href="https://zh.javascript.info/arraybuffer-binary-arrays" target="_blank" rel="noreferrer">视图对象本身并不存储任何东西。它是一副“眼镜”，透过它来解释存储在 ArrayBuffer 中的字节。</a> 例如：</p><ul><li><p><strong><code>Uint8Array</code></strong> —— 将 <code>ArrayBuffer</code> 中的每个字节视为 0 到 255 之间的单个数字（每个字节是 8 位，因此只能容纳那么多）。这称为 “8 位无符号整数”。</p></li><li><p><strong><code>Uint16Array</code></strong> —— 将每 2 个字节视为一个 0 到 65535 之间的整数。这称为 “16 位无符号整数”。</p></li><li><p><strong><code>Uint32Array</code></strong> —— 将每 4 个字节视为一个 0 到 4294967295 之间的整数。这称为 “32 位无符号整数”。</p></li><li><p><strong><code>Float64Array</code></strong> —— 将每 8 个字节视为一个 <code>5.0x10&lt;sup&gt;-324&lt;/sup&gt;</code> 到 <code>1.8x10&lt;sup&gt;308&lt;/sup&gt;</code> 之间的浮点数。</p></li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">let view = new Uint32Array(buffer); // 将 buffer 视为一个 32 位整数的序列</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">alert(Uint32Array.BYTES_PER_ELEMENT); // 每个整数 4 个字节</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">alert(view.length); // 4，它存储了 4 个整数</span></span>
<span class="line"><span style="color:#A6ACCD;">alert(view.byteLength); // 16，字节中的大小</span></span></code></pre></div>`,24),r=[o];function t(p,c,i,d,b,u){return e(),s("div",null,r)}const y=a(n,[["render",t]]);export{h as __pageData,y as default};
